701→  timeoutMs: number,
702→): Promise<void> {
703→  const start = Date.now();
704→  while (Date.now() - start < timeoutMs) {
705→    if (typeof process.exitCode === "number") {
706→      const stderr = process.stderr
707→        ? await new Response(process.stderr).text()
708→        : "";
709→      throw new Error(
710→        `Server exited early with code ${process.exitCode}\n${stderr}`,
711→      );
712→    }
